import re

with open('/Users/krisztiankoos/projects/learn-ukrainian/curriculum/l2-uk-en/a1/weather-and-nature.md', 'r', encoding='utf-8') as f:
    text = f.read()

def insert_after(header, injection, text):
    # insert injection at the end of the section (before the next header or end of file)
    # wait, it's easier to just insert it after the first paragraph following the header
    pattern = re.compile(rf'(### {header}.*?\n\n.*?)(?=\n)', flags=re.DOTALL)
    match = pattern.search(text)
    if match:
        return text[:match.end()] + f"\n\n{injection}" + text[match.end():]
    return text

